// Pick the first SAFE attachment to extract: PDF only, <= 10MB. Everything else
// (docx, images, archives, executables, oversized) is skipped → body fallback.
const atts = ((($('Inbound Mail Webhook').first().json.body) || {}).attachments) || [];
const MAX = 10 * 1024 * 1024;
const pick = atts.find(a => a && a.mimeType === 'application/pdf' && Number(a.size || 0) > 0 && Number(a.size || 0) <= MAX);
return [{ json: { r2Key: pick ? pick.r2Key : '', att_filename: pick ? (pick.filename || 'attachment.pdf') : '', has_att: !!pick } }];

const b = ($('Inbound Mail Webhook').first().json.body) || {};
// attachment text comes from "Extract from File" (runs with continueOnError; empty if no PDF)
let attText = '';
try { const e = $('Extract from File').first().json || {}; attText = String(e.text || e.data || e.extractedText || ''); } catch (err) {}
attText = attText.slice(0, 6000);
let fn = '';
try { fn = (($('Pick Attachment').first().json) || {}).att_filename || ''; } catch (err) {}
const sys = `You are an extraction service that pulls actionable items from an inbound message for the Gibbs family (kids: ronin, rory). The message may be a school notice, community flyer, bill, event, or general info, and may include an attached PDF. Output ONLY a JSON array (no markdown). Each item: {"type":"date|dues|assignment|event|site-pointer|info","title":string,"dueAt":ISO-8601 date or datetime or null,"student":"ronin|rory|both|unknown","actionRequired":boolean,"amount":string|null,"teacher":string|null,"class":string|null,"source_hint":short verbatim quote,"confidence":0..1}. Resolve relative dates against the email date. If nothing actionable, return [].`;
const bodyText = String(b.text || '').slice(0, 5000);
let user = `EMAIL DATE: ${b.date || ''}\nFROM: ${b.from || ''}\nSUBJECT: ${b.subject || ''}\nTO: ${b.envelopeTo || ''}\n\nBODY:\n${bodyText}`;
if (attText.trim()) user += `\n\n--- ATTACHED PDF (${fn}) ---\n${attText}`;
return [{ json: { model: 'qwen3-30b-instruct', temperature: 0.1, max_tokens: 1500, messages: [ { role: 'system', content: sys }, { role: 'user', content: user } ] } }];

const resp = $input.first().json;
let content = (((resp.choices || [])[0] || {}).message || {}).content || '';
content = content.replace(/```json/gi, '').replace(/```/g, '').trim();
const s = content.indexOf('['), e = content.lastIndexOf(']');
let arr = [];
if (s >= 0 && e > s) {
  try { arr = JSON.parse(content.slice(s, e + 1)); }
  catch (err) { arr = [{ type: 'info', title: 'PARSE_ERROR', source_hint: content.slice(0, 300), confidence: 0 }]; }
}
if (!Array.isArray(arr)) arr = [];
const src = ($('Inbound Mail Webhook').first().json.body) || {};
// stable per-EMAIL identity (msgId) — the "Delete Prior" node clears this email's
// old rows before insert, so re-processing/retries replace rather than duplicate.
const source_msg_id = String(src.messageId || `${src.from || ''}|${src.subject || ''}|${src.date || ''}`);
return arr.map(r => ({ json: {
  source_msg_id,
  type: r.type || 'info',
  title: r.title || '',
  due_at: r.dueAt || null,
  student: r.student || 'unknown',
  action_required: r.actionRequired === true,
  amount: r.amount || null,
  teacher: r.teacher || null,
  course: r.class || null,
  source_hint: r.source_hint || null,
  confidence: (typeof r.confidence === 'number' ? r.confidence : null),
  source_channel: src.envelopeTo || '',
  source_subject: src.subject || '',
  source_from: src.from || ''
} }));
